238→// Items is the resolver for the items field.
239→func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
240→	claims, err := requireAuth(ctx)
241→	if err != nil {
242→		return nil, err
243→	}
244→
245→	result, err := r.ItemService.List(ctx, claims.UserID,
246→		toItemFilter(filter),
247→		derefIntOr(limit, 20),
248→		derefIntOr(offset, 0),
249→		toItemSort(sort))
250→	if err != nil {
251→		return nil, fmt.Errorf("resolver: items: %w", err)
252→	}
253→
254→	return &model.SearchResult{
255→		Items:   toGraphQLItems(result.Items),
256→		Total:   result.Total,
257→		HasMore: result.HasMore,
258→	}, nil
259→}
260→
261→// Search is the resolver for the search field.
262→func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
263→	claims, err := requireAuth(ctx)
264→	if err != nil {
265→		return nil, err
266→	}
267→
268→	th := derefFloat64Or(threshold, 0.0)
269→	lim := derefIntOr(limit, 20)
270→	f := toItemFilter(filter)
271→
272→	// Use semantic search when threshold > 0 and embedder is available
273→	if th > 0 && r.Embedder != nil && query != "" {
274→		embedding, err := r.Embedder.Embed(ctx, query)
275→		if err != nil {
276→			slog.ErrorContext(ctx, "resolver: search: embedding failed, falling back to FTS",
277→				"error", err,
278→			)
279→		} else {
280→			result, err := r.ItemService.SemanticSearch(ctx, claims.UserID, embedding, f, lim, th)
281→			if err != nil {
282→				return nil, fmt.Errorf("resolver: semantic search: %w", err)
283→			}
284→			return &model.SearchResult{
285→				Items:   toGraphQLItems(result.Items),
286→				Total:   result.Total,
287→				HasMore: result.HasMore,
288→			}, nil
289→		}
290→	}
291→
292→	// Fall back to full-text search
293→	result, err := r.ItemService.Search(ctx, claims.UserID, query, f, lim, th)
294→	if err != nil {
295→		return nil, fmt.Errorf("resolver: search: %w", err)
296→	}
297→
298→	return &model.SearchResult{
299→		Items:   toGraphQLItems(result.Items),
300→		Total:   result.Total,
301→		HasMore: result.HasMore,
302→	}, nil
303→}
304→
305→// Mutation returns generated.MutationResolver implementation.
306→func (r *Resolver) Mutation() generated.MutationResolver { return &mutationResolver{r} }
307→
308→// Query returns generated.QueryResolver implementation.
309→func (r *Resolver) Query() generated.QueryResolver { return &queryResolver{r} }
310→
311→type mutationResolver struct{ *Resolver }
312→type queryResolver struct{ *Resolver }
