 43→func TestIntegrationRoundTrip(t *testing.T) {
 44→	if testing.Short() {
 45→		t.Skip("skipping integration test in short mode")
 46→	}
 47→
 48→	endpoint := os.Getenv("S3_ENDPOINT")
 49→	if endpoint == "" {
 50→		t.Skip("S3_ENDPOINT not set, skipping integration test")
 51→	}
 52→
 53→	accessKey := os.Getenv("S3_ACCESS_KEY")
 54→	if accessKey == "" {
 55→		accessKey = "minioadmin"
 56→	}
 57→	secretKey := os.Getenv("S3_SECRET_KEY")
 58→	if secretKey == "" {
 59→		secretKey = "minioadmin"
 60→	}
 61→	bucket := os.Getenv("S3_BUCKET")
 62→	if bucket == "" {
 63→		bucket = "flotsam-dev"
 64→	}
 65→
 66→	client, err := New(Config{
 67→		Endpoint:       endpoint,
 68→		Bucket:         bucket,
 69→		AccessKey:      accessKey,
 70→		SecretKey:      secretKey,
 71→		Region:         "us-east-1",
 72→		ForcePathStyle: true,
 73→	})
 74→	if err != nil {
 75→		t.Fatalf("failed to create client: %v", err)
 76→	}
 77→
 78→	ctx := context.Background()
 79→	ownerID := uuid.New()
 80→	itemID := uuid.New()
 81→	key := BookmarkKey(ownerID, itemID)
 82→	content := []byte("<html><body>Hello, world!</body></html>")
 83→
 84→	// Upload
 85→	err = client.Upload(ctx, key, bytes.NewReader(content), "text/html")
 86→	if err != nil {
 87→		t.Fatalf("Upload failed: %v", err)
 88→	}
 89→
 90→	// Exists — should be true
 91→	exists, err := client.Exists(ctx, key)
 92→	if err != nil {
 93→		t.Fatalf("Exists failed: %v", err)
 94→	}
 95→	if !exists {
 96→		t.Fatal("expected object to exist after upload")
 97→	}
 98→
 99→	// Download
100→	rc, err := client.Download(ctx, key)
101→	if err != nil {
102→		t.Fatalf("Download failed: %v", err)
103→	}
104→	defer func() { _ = rc.Close() }()
105→
106→	downloaded, err := io.ReadAll(rc)
107→	if err != nil {
108→		t.Fatalf("reading download body: %v", err)
109→	}
110→	if !bytes.Equal(downloaded, content) {
111→		t.Errorf("downloaded content mismatch: got %q, want %q", downloaded, content)
112→	}
113→
114→	// PresignedURL — should return a non-empty URL
115→	url, err := client.PresignedURL(ctx, key, 60*time.Second)
116→	if err != nil {
117→		t.Fatalf("PresignedURL failed: %v", err)
118→	}
119→	if url == "" {
120→		t.Fatal("expected non-empty presigned URL")
121→	}
122→
123→	// Delete
124→	err = client.Delete(ctx, key)
125→	if err != nil {
126→		t.Fatalf("Delete failed: %v", err)
127→	}
128→
129→	// Exists — should be false
130→	exists, err = client.Exists(ctx, key)
131→	if err != nil {
132→		t.Fatalf("Exists after delete failed: %v", err)
133→	}
134→	if exists {
135→		t.Fatal("expected object to not exist after delete")
136→	}
137→}
