	}

	if err := r.ItemService.Delete(ctx, claims.UserID, itemID); err != nil {
		return false, fmt.Errorf("resolver: delete item: %w", err)
	}
	return true, nil
}

// UpdateSensitivity is the resolver for the updateSensitivity field.
func (r *mutationResolver) UpdateSensitivity(ctx context.Context, id string, sensitivity model.SensitivityLevel) (*model.Item, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	itemID, err := uuid.Parse(id)
	if err != nil {
		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
	}

	it, err := r.ItemService.UpdateSensitivity(ctx, claims.UserID, itemID, sensitivityToString(&sensitivity))
	if err != nil {
		return nil, fmt.Errorf("resolver: update sensitivity: %w", err)
	}
	return toGraphQLItem(it), nil
}

// TagItem is the resolver for the tagItem field.
func (r *mutationResolver) TagItem(ctx context.Context, id string, tags []string) (*model.Item, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	itemID, err := uuid.Parse(id)
	if err != nil {
		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
	}

	it, err := r.ItemService.Tag(ctx, claims.UserID, itemID, tags)
	if err != nil {
		return nil, fmt.Errorf("resolver: tag item: %w", err)
	}
	return toGraphQLItem(it), nil
}

// Item is the resolver for the item field.
func (r *queryResolver) Item(ctx context.Context, id string) (*model.Item, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	itemID, err := uuid.Parse(id)
	if err != nil {
		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
	}

	it, err := r.ItemService.GetByID(ctx, claims.UserID, itemID)
	if err != nil {
		return nil, fmt.Errorf("resolver: item: %w", err)
	}
	if it == nil {
		return nil, nil
	}
	return toGraphQLItem(it), nil
}

// Items is the resolver for the items field.
func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	result, err := r.ItemService.List(ctx, claims.UserID,
		toItemFilter(filter),
		derefIntOr(limit, 20),
		derefIntOr(offset, 0),
		toItemSort(sort))
	if err != nil {
		return nil, fmt.Errorf("resolver: items: %w", err)
	}

	return &model.SearchResult{
		Items:   toGraphQLItems(result.Items),
		Total:   result.Total,
		HasMore: result.HasMore,
	}, nil
}

// Search is the resolver for the search field.
func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	th := derefFloat64Or(threshold, 0.0)
	lim := derefIntOr(limit, 20)
	f := toItemFilter(filter)

	// Use semantic search when threshold > 0 and embedder is available
	if th > 0 && r.Embedder != nil && query != "" {
		embedding, err := r.Embedder.Embed(ctx, query)
		if err != nil {
			slog.ErrorContext(ctx, "resolver: search: embedding failed, falling back to FTS",
				"error", err,
			)
		} else {
			result, err := r.ItemService.SemanticSearch(ctx, claims.UserID, embedding, f, lim, th)
			if err != nil {
				return nil, fmt.Errorf("resolver: semantic search: %w", err)
			}
			return &model.SearchResult{
				Items:   toGraphQLItems(result.Items),
				Total:   result.Total,
				HasMore: result.HasMore,
			}, nil
		}
	}

	// Fall back to full-text search
	result, err := r.ItemService.Search(ctx, claims.UserID, query, f, lim, th)
	if err != nil {
		return nil, fmt.Errorf("resolver: search: %w", err)
	}

	return &model.SearchResult{
		Items:   toGraphQLItems(result.Items),
		Total:   result.Total,
		HasMore: result.HasMore,
	}, nil
}

// Mutation returns generated.MutationResolver implementation.
func (r *Resolver) Mutation() generated.MutationResolver { return &mutationResolver{r} }

// Query returns generated.QueryResolver implementation.
func (r *Resolver) Query() generated.QueryResolver { return &queryResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }

