package storage

import (
	"testing"

	"github.com/google/uuid"
)

func TestValidateKeyOwnership(t *testing.T) {
	ownerID := uuid.MustParse("aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee")
	otherID := uuid.MustParse("11111111-2222-3333-4444-555555555555")

	tests := []struct {
		name    string
		key     string
		ownerID uuid.UUID
		wantErr bool
		errMsg  string
	}{
		{
			name:    "valid upload key",
			key:     ownerID.String() + "/uploads/somefile.mp3",
			ownerID: ownerID,
			wantErr: false,
		},
		{
			name:    "valid voice note key",
			key:     ownerID.String() + "/voice_notes/" + uuid.New().String() + "/audio.webm",
			ownerID: ownerID,
			wantErr: false,
		},
		{
			name:    "different owner",
			key:     otherID.String() + "/uploads/somefile.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "does not belong to owner",
		},
		{
			name:    "empty key",
			key:     "",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "key is empty",
		},
		{
			name:    "path traversal with dot-dot",
			key:     ownerID.String() + "/uploads/../../other-user/secret.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
		{
			name:    "path traversal at start",
			key:     "../" + ownerID.String() + "/uploads/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
		{
			name:    "owner prefix only no subpath",
			key:     ownerID.String() + "/",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "invalid structure",
		},
		{
			name:    "owner prefix with type but no file",
			key:     ownerID.String() + "/uploads",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "invalid structure",
		},
		{
			name:    "completely wrong prefix",
			key:     "not-a-uuid/uploads/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "does not belong to owner",
		},
		{
			name:    "embedded dot-dot in filename",
			key:     ownerID.String() + "/uploads/..sneaky/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := ValidateKeyOwnership(tt.key, tt.ownerID)
			if tt.wantErr {
				if err == nil {
					t.Fatalf("expected error containing %q, got nil", tt.errMsg)
				}
				if tt.errMsg != "" && !contains(err.Error(), tt.errMsg) {
					t.Fatalf("expected error containing %q, got %q", tt.errMsg, err.Error())
				}
			} else {
				if err != nil {
					t.Fatalf("unexpected error: %v", err)
				}
			}
		})
	}
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && searchString(s, substr)
}

func searchString(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

