func TestValidateKeyOwnership(t *testing.T) {
	ownerID := uuid.MustParse("aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee")
	otherID := uuid.MustParse("11111111-2222-3333-4444-555555555555")

	tests := []struct {
		name    string
		key     string
		ownerID uuid.UUID
		wantErr bool
		errMsg  string
	}{
		{
			name:    "valid upload key",
			key:     ownerID.String() + "/uploads/somefile.mp3",
			ownerID: ownerID,
		},
		{
			name:    "valid voice note key",
			key:     ownerID.String() + "/voice_notes/" + uuid.New().String() + "/audio.webm",
			ownerID: ownerID,
		},
		{
			name:    "different owner rejected",
			key:     otherID.String() + "/uploads/somefile.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "does not belong to owner",
		},
		{
			name:    "empty key rejected",
			key:     "",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "key is empty",
		},
		{
			name:    "path traversal rejected",
			key:     ownerID.String() + "/uploads/../../other-user/secret.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
		{
			name:    "path traversal at start rejected",
			key:     "../" + ownerID.String() + "/uploads/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
		{
			name:    "owner prefix only rejected",
			key:     ownerID.String() + "/",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "invalid structure",
		},
		{
			name:    "no subpath rejected",
			key:     ownerID.String() + "/uploads",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "invalid structure",
		},
		{
			name:    "wrong prefix rejected",
			key:     "not-a-uuid/uploads/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "does not belong to owner",
		},
		{
			name:    "embedded dot-dot in segment rejected",
			key:     ownerID.String() + "/uploads/..sneaky/file.mp3",
			ownerID: ownerID,
			wantErr: true,
			errMsg:  "path traversal",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
